import { assert } from './assert.js';
// regexes
const ACCOUNT_NAME_REGEX = /^[\w-]+$/;
// type guards
export function isAccountName(candidate) {
    if (!(typeof candidate === 'string')) {
        return false;
    }
    return Boolean(candidate.match(ACCOUNT_NAME_REGEX));
}
// assertion functions
export function assertAccountName(candidate) {
    assert(isAccountName(candidate), `"${candidate}" is not an account name; expected to match ${ACCOUNT_NAME_REGEX}`);
}
// factory functions
export function AccountName(candidate) {
    assertAccountName(candidate);
    return candidate;
}
